#include<cstdio>
#include<cstring>
#include<queue>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=110,INF=0x3f3f3f3f;int dp[1<<10][N],n,m,K;bool vis[N];
typedef long long LL;typedef std::pair<int,int> pii;
std::priority_queue<pii,std::vector<pii>,std::greater<pii> > h; 
std::vector<int> a;std::vector<pii> G[N];
inline void dij(int *dis)
{
	memset(vis,0,n+3);while(!h.empty())
	{
		int u=h.top().second;h.pop();if(vis[u])continue;vis[u]=true;
		for(pii x:G[u]){int v=x.first,w=x.second;if(dis[u]+w<dis[v])h.push({dis[v]=dis[u]+w,v});}
	}
	
}
int main()
{
	n=read();m=read();K=read();rep(1,m,i)
	{
		int x=read(),y=read(),z=read();
		G[x].push_back({y,z});G[y].push_back({x,z});
	}
	rep(1,K,i)a.push_back(read());
	memset(dp,0x3f,sizeof(dp));for(int i=0;i<K;++i)dp[1<<i][a[i]]=0;
	for(int S=0;S<(1<<K);++S)
	{
		
		for(int T=S&(S-1);T;T=(T-1)&S)rep(1,n,i)dp[S][i]=min(dp[S][i],dp[S^T][i]+dp[T][i]);
		rep(1,n,i)if(dp[S][i]!=INF)h.push({dp[S][i],i});dij(dp[S]);
	}
	printf("%d\n",dp[(1<<K)-1][a[0]]);return 0;
}
